@Beta
  public static <A extends @Nullable Object, B extends @Nullable Object> void forEachPair(
      Stream<A> streamA, Stream<B> streamB, BiConsumer<? super A, ? super B> consumer) {
    checkNotNull(consumer);

    if (streamA.isParallel() || streamB.isParallel()) {
      zip(streamA, streamB, TemporaryPair::new).forEach(pair -> consumer.accept(pair.a, pair.b));
    } else {
      Iterator<A> iterA = streamA.iterator();
      Iterator<B> iterB = streamB.iterator();
      while (iterA.hasNext() && iterB.hasNext()) {
        consumer.accept(iterA.next(), iterB.next());
      }
    }
  }

public static <T> T mode(final T... items) {
    if (ArrayUtils.isNotEmpty(items)) {
        final HashMap<T, MutableInt> occurrences = new HashMap<>(items.length);
        for (final T t : items) {
            ArrayUtils.increment(occurrences, t);
        }
        T result = null;
        int max = 0;
        for (final Map.Entry<T, MutableInt> e : occurrences.entrySet()) {
            final int cmp = e.getValue().intValue();
            if (cmp == max) {
                result = null;
            } else if (cmp > max) {
                max = cmp;
                result = e.getKey();
            }
        }
        return result;
    }
    return null;
}

public static String chomp(final String str) {
    if (isEmpty(str)) {
        return str;
    }
    if (str.length() == 1) {
        final char ch = str.charAt(0);
        if (ch == CharUtils.CR || ch == CharUtils.LF) {
            return EMPTY;
        }
        return str;
    }
    int lastIdx = str.length() - 1;
    final char last = str.charAt(lastIdx);
    if (last == CharUtils.LF) {
        if (str.charAt(lastIdx - 1) == CharUtils.CR) {
            lastIdx--;
        }
    } else if (last != CharUtils.CR) {
        lastIdx++;
    }
    return str.substring(0, lastIdx);
}

private static HashedWheelBucket[] createWheel(int ticksPerWheel) {
    if (ticksPerWheel <= 0) {
        throw new IllegalArgumentException(
            "ticksPerWheel must be greater than 0: " + ticksPerWheel);
    }
    if (ticksPerWheel > 1073741824) {
        throw new IllegalArgumentException(
            "ticksPerWheel may not be greater than 2^30: " + ticksPerWheel);
    }

    ticksPerWheel = normalizeTicksPerWheel(ticksPerWheel);
    HashedWheelBucket[] wheel = new HashedWheelBucket[ticksPerWheel];
    for (int i = 0; i < wheel.length; i++) {
        wheel[i] = new HashedWheelBucket();
    }
    return wheel;
}

private boolean isActive(String[][] keyPairs, URL url) {
    if (keyPairs.length == 0) {
        return true;
    }
    for (String[] keyPair : keyPairs) {
        // @Active(value="key1:value1, key2:value2")
        String key;
        String keyValue = null;
        if (keyPair.length > 1) {
            key = keyPair[0];
            keyValue = keyPair[1];
        } else {
            key = keyPair[0];
        }

        String realValue = url.getParameter(key);
        if (StringUtils.isEmpty(realValue)) {
            realValue = url.getAnyMethodParameter(key);
        }
        if ((keyValue != null && keyValue.equals(realValue))
                || (keyValue == null && ConfigUtils.isNotEmpty(realValue))) {
            return true;
        }
    }
    return false;
}

public String toString() {
    final long currentTime = System.nanoTime();
    long remaining = deadline - currentTime + timer.startTime;
    String simpleClassName = ClassUtils.simpleClassName(this.getClass());

    StringBuilder buf = new StringBuilder(192)
        .append(simpleClassName)
        .append('(')
        .append("deadline: ");
    if (remaining > 0) {
        buf.append(remaining)
            .append(" ns later");
    } else if (remaining < 0) {
        buf.append(-remaining)
            .append(" ns ago");
    } else {
        buf.append("now");
    }

    if (isCancelled()) {
        buf.append(", cancelled");
    }

    return buf.append(", task: ")
        .append(task())
        .append(')')
        .toString();
}

static final TypeAdapterFactory FACTORY =
      new TypeAdapterFactory() {
        @Override
        public <T> TypeAdapter<T> create(Gson gson, TypeToken<T> typeToken) {
          Class<? super T> rawType = typeToken.getRawType();
          if (!Enum.class.isAssignableFrom(rawType) || rawType == Enum.class) {
            return null;
          }
          if (!rawType.isEnum()) {
            rawType = rawType.getSuperclass(); // handle anonymous subclasses
          }
          @SuppressWarnings({"rawtypes", "unchecked"})
          TypeAdapter<T> adapter = (TypeAdapter<T>) new EnumTypeAdapter(rawType);
          return adapter;
        }
      };

LockFreeBitArray(long bits) {
  checkArgument(bits > 0, "data length is zero!");
  // Avoid delegating to this(long[]), since AtomicLongArray(long[]) will clone its input and
  // thus double memory usage.
  this.data =
      new AtomicLongArray(Ints.checkedCast(LongMath.divide(bits, 64, RoundingMode.CEILING)));
  this.bitCount = new LongAdder();
}

// Used by serialization
LockFreeBitArray(long[] data) {
  checkArgument(data.length > 0, "data length is zero!");
  this.data = new AtomicLongArray(data);
  this.bitCount = new LongAdder();
  long bitCount = 0;
  for (long value : data) {
    bitCount += Long.bitCount(value);
  }
  this.bitCount.add(bitCount);
}

protected BasePeriod(ReadableInstant startInstant, ReadableInstant endInstant, PeriodType type) {
    super();
    type = checkPeriodType(type);
    if (startInstant == null && endInstant == null) {
        iType = type;
        iValues = new int[size()];
    } else {
        long startMillis = DateTimeUtils.getInstantMillis(startInstant);
        long endMillis = DateTimeUtils.getInstantMillis(endInstant);
