public int size2SizeIdx(int size) {
    if (size == 0) {
        return 0;
    }
    if (size > chunkSize) {
        return nSizes;
    }

    size = alignSizeIfNeeded(size, directMemoryCacheAlignment);

    if (size <= lookupMaxSize) {
        //size-1 / MIN_TINY
        return size2idxTab[size - 1 >> LOG2_QUANTUM];
    }

    int x = log2((size << 1) - 1);
    int shift = x < LOG2_SIZE_CLASS_GROUP + LOG2_QUANTUM + 1
            ? 0 : x - (LOG2_SIZE_CLASS_GROUP + LOG2_QUANTUM);

    int group = shift << LOG2_SIZE_CLASS_GROUP;

    int log2Delta = x < LOG2_SIZE_CLASS_GROUP + LOG2_QUANTUM + 1
            ? LOG2_QUANTUM : x - LOG2_SIZE_CLASS_GROUP - 1;

    int mod = size - 1 >> log2Delta & (1 << LOG2_SIZE_CLASS_GROUP) - 1;

    return group + mod;
}

private int pages2pageIdxCompute(int pages, boolean floor) {
    int pageSize = pages << pageShifts;
    if (pageSize > chunkSize) {
        return nPSizes;
    }

    int x = log2((pageSize << 1) - 1);

    int shift = x < LOG2_SIZE_CLASS_GROUP + pageShifts
            ? 0 : x - (LOG2_SIZE_CLASS_GROUP + pageShifts);

    int group = shift << LOG2_SIZE_CLASS_GROUP;

    int log2Delta = x < LOG2_SIZE_CLASS_GROUP + pageShifts + 1?
            pageShifts : x - LOG2_SIZE_CLASS_GROUP - 1;

    int mod = pageSize - 1 >> log2Delta & (1 << LOG2_SIZE_CLASS_GROUP) - 1;

    int pageIdx = group + mod;

    if (floor && pageIdx2sizeTab[pageIdx] > pages << pageShifts) {
        pageIdx--;
    }

    return pageIdx;
}

long allocate() {
    if (numAvail == 0 || !doNotDestroy) {
        return -1;
    }

    final int bitmapIdx = getNextAvail();
    if (bitmapIdx < 0) {
        removeFromPool(); // Subpage appear to be in an invalid state. Remove to prevent repeated errors.
        throw new AssertionError("No next available bitmap index found (bitmapIdx = " + bitmapIdx + "), " +
                "even though there are supposed to be (numAvail = " + numAvail + ") " +
                "out of (maxNumElems = " + maxNumElems + ") available indexes.");
    }
    int q = bitmapIdx >>> 6;
    int r = bitmapIdx & 63;
    assert (bitmap[q] >>> r & 1) == 0;
    bitmap[q] |= 1L << r;

    if (-- numAvail == 0) {
        removeFromPool();
    }

    return toHandle(bitmapIdx);
}

private long allocateRun(int runSize) {
    int pages = runSize >> pageShifts;
    int pageIdx = arena.sizeClass.pages2pageIdx(pages);

    runsAvailLock.lock();
    try {
        //find first queue which has at least one big enough run
        int queueIdx = runFirstBestFit(pageIdx);
        if (queueIdx == -1) {
            return -1;
        }

        //get run with min offset in this queue
        IntPriorityQueue queue = runsAvail[queueIdx];
        long handle = queue.poll();
        assert handle != IntPriorityQueue.NO_VALUE;
        handle <<= BITMAP_IDX_BIT_LENGTH;
        assert !isUsed(handle) : "invalid handle: " + handle;

        removeAvailRun0(handle);

        handle = splitLargeRun(handle, pages);

        int pinnedSize = runSize(pageShifts, handle);
        freeBytes -= pinnedSize;
        return handle;
    } finally {
        runsAvailLock.unlock();
    }
}

private int calculateRunSize(int sizeIdx) {
    int maxElements = 1 << pageShifts - SizeClasses.LOG2_QUANTUM;
    int runSize = 0;
    int nElements;

    final int elemSize = arena.sizeClass.sizeIdx2size(sizeIdx);

    //find lowest common multiple of pageSize and elemSize
    do {
        runSize += pageSize;
        nElements = runSize / elemSize;
    } while (nElements < maxElements && runSize != nElements * elemSize);

    while (nElements > maxElements) {
        runSize -= pageSize;
        nElements = runSize / elemSize;
    }

    assert nElements > 0;
    assert runSize <= chunkSize;
    assert runSize >= elemSize;

    return runSize;
}

@Override
    protected void parse(String rawRule) throws NacosException {
        this.isPatternMatch(rawRule, EXPRESSION_PATTERN);
        String[] keyValueArray = rawRule.trim().split(EQUAL_PATTERN);
        if (keyValueArray.length != KEY_VALUE_ARRAY_LENGTH) {
            throw new NacosException(NacosException.INVALID_PARAM, String.format(
                "gray rule parse failed: raw rule[%s] doesn't match pattern[%s].",
                rawRule, KEY_PATTERN + EQUAL_PATTERN + VALUE_PATTERN));
        }
        isPatternMatch(keyValueArray[0].trim(), KEY_PATTERN);
        isPatternMatch(keyValueArray[1].trim(), VALUE_PATTERN);
        this.tagKey = keyValueArray[0].trim();
        this.tagValueSet = Arrays.stream(keyValueArray[1].trim().split(VALUE_SPLITER_PATTERN))
            .map(String::trim).filter(StringUtils::isNotBlank).collect(Collectors.toSet());
    }

public static Map<String, SubscriberStatus> listSubStatus(String ip) {
    Map<String, SubscriberStatus> status = new HashMap<>(100);

    // record here is non-null
    ClientRecord record = getClientRecord(ip);
    for (Map.Entry<String, String> entry : record.getGroupKey2md5Map().entrySet()) {
        String groupKey = entry.getKey();
        String clientMd5 = entry.getValue();
        long lastPollingTs = record.getGroupKey2pollingTsMap().get(groupKey);
        boolean isUpdate = ConfigCacheService.isUptodate(groupKey, clientMd5);

        status.put(groupKey,
            new SubscriberStatus(groupKey, isUpdate, clientMd5, lastPollingTs));
    }

    return status;
}

public Collection<NacosMember> getNodeList(String ipKeyWord) throws NacosException {
    Collection<? extends NacosMember> members = clusterHandler.getNodeList(ipKeyWord);
    List<NacosMember> result = new ArrayList<>();
    members.forEach(member -> {
        if (StringUtils.isBlank(ipKeyWord)) {
            result.add(member);
            return;
        }
        final String address = member.getAddress();
        if (StringUtils.equals(address, ipKeyWord)
            || StringUtils.startsWith(address, ipKeyWord)) {
            result.add(member);
        }
    });
    result.sort(Comparator.comparing(NacosMember::getAddress));
    return result;
}

private static Stream<? extends SchemaElement> getKeyspaceElements(KeyspaceMetadata ks, boolean onlyKeyspace)
    {
        Stream<? extends SchemaElement> s = Stream.of(ks);

        if (!onlyKeyspace)
        {
            s = Stream.concat(s, ks.types.sortedStream());
            s = Stream.concat(s, ks.userFunctions.udfs().sorted(SchemaElement.NAME_COMPARATOR));
            s = Stream.concat(s, ks.userFunctions.udas().sorted(SchemaElement.NAME_COMPARATOR));
            s = Stream.concat(s, ks.tables.stream().sorted(SchemaElement.NAME_COMPARATOR)
                                                   .flatMap(tm -> getTableElements(ks, tm)));
        }

        return s;
    }

private <T extends BaseRecord> T getRecord(
    final String path, final Class<T> clazz) throws IOException {
  try (BufferedReader reader = getReader(path)) {
    String line;
    while ((line = reader.readLine()) != null) {
      if (!line.startsWith("#") && line.length() > 0) {
        try {
          return newRecord(line, clazz, false);
        } catch (Exception ex) {
          LOG.error("Cannot parse line {} in file {}", line, path, ex);
        }
      }
    }
  }
  throw new IOException("Cannot read " + path + " for record " +
      clazz.getSimpleName());
}

private Consumer<List<DatanodeInfoWithStorage>> createSecondaryNodeSorter() {
  Consumer<List<DatanodeInfoWithStorage>> secondarySort = null;
  if (readConsiderStorageType) {
    Comparator<DatanodeInfoWithStorage> comp =
        Comparator.comparing(DatanodeInfoWithStorage::getStorageType, (s1, s2) -> {
          if (s1 == null) {
            return (s2 == null) ? 0 : -1;
          } else if (s2 == null) {
            return 1;
          } else {
            return s1.compareTo(s2);
          }
        });
    secondarySort = list -> Collections.sort(list, comp);
  }
  if (readConsiderLoad) {
    Comparator<DatanodeInfoWithStorage> comp =
        Comparator.comparingInt(DatanodeInfo::getXceiverCount);
    secondarySort = list -> Collections.sort(list, comp);
  }
  return secondarySort;
}

public static <T extends @Nullable Object> void testComparator(
    Comparator<? super T> comparator, List<T> valuesInExpectedOrder) {
  // This does an O(n^2) test of all pairs of values in both orders
  for (int i = 0; i < valuesInExpectedOrder.size(); i++) {
    T t = valuesInExpectedOrder.get(i);

    for (int j = 0; j < i; j++) {
      T lesser = valuesInExpectedOrder.get(j);
      assertTrue(
          comparator + ".compare(" + lesser + ", " + t + ")", comparator.compare(lesser, t) < 0);
    }

    assertEquals(comparator + ".compare(" + t + ", " + t + ")", 0, comparator.compare(t, t));

    for (int j = i + 1; j < valuesInExpectedOrder.size(); j++) {
      T greater = valuesInExpectedOrder.get(j);
      assertTrue(
          comparator + ".compare(" + greater + ", " + t + ")",
          comparator.compare(greater, t) > 0);
    }
  }
}

public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    mw.ident(buf, indent);
    buf.append("if (");
    condition.toString(mw, buf, indent);
    buf.append(") {").append('\n');

    for (int i = 0; i < statements.size(); i++) {
        if (i != 0) {
            buf.append('\n');
        }
        Statement stmt = statements.get(i);
        stmt.toString(mw, buf, indent + 1);
    }

    buf.append('\n');
    mw.ident(buf, indent);
    buf.append("}");

    if (elseStmt != null) {
        buf.append(" else {\n");
        for (int i = 0; i < elseStmt.statements.size(); i++) {
            if (i != 0) {
                buf.append('\n');
            }
            Statement stmt = elseStmt.statements.get(i);
            stmt.toString(mw, buf, indent + 1);
        }
        buf.append('\n');
        mw.ident(buf, indent);
        buf.append("}");
    }
}

public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    buf.append("new ").append(type).append('[');

    if (size != null) {
        size.toString(mw, buf, indent);
    }
    buf.append(']');
    if (values != null) {
        int length = values.length;
        if (length > 0) {
            buf.append('{');

            buf.append('\n');
            mw.ident(buf, indent + 2);

            for (int i = 0; i < length; i++) {
                if (i != 0) {
                    buf.append(",\n");
                    mw.ident(buf, indent + 2);
                }
                values[i].toString(mw, buf, indent + 2);
            }

            buf.append('\n');
            mw.ident(buf, indent);
            buf.append('}');
        } else if (length == 0) {
            buf.append("{}");
        }
    }
}

