private void gwSetValue(MethodWriter mw, String TYPE_OBJECT, FieldReader fieldReader) {
    Method method = fieldReader.method;
    Field field = fieldReader.field;
    Class fieldClass = fieldReader.fieldClass;
    String fieldClassDesc = ASMUtils.desc(fieldClass);

    if (method != null) {
        Class<?> returnType = method.getReturnType();
        String methodDesc = '(' + fieldClassDesc + ')' + ASMUtils.desc(returnType);
        mw.invokevirtual(TYPE_OBJECT, method.getName(), methodDesc);
        if (returnType != Void.TYPE) { // builder
            mw.pop();
        }
    } else {
        mw.putfield(TYPE_OBJECT, field.getName(), fieldClassDesc);
    }
}

static <T extends @Nullable Object, E> Collector<T, ?, ImmutableMultiset<E>> toImmutableMultiset(
    Function<? super T, ? extends E> elementFunction, ToIntFunction<? super T> countFunction) {
  checkNotNull(elementFunction);
  checkNotNull(countFunction);
  return Collector.of(
      LinkedHashMultiset::create,
      (multiset, t) ->
          multiset.add(checkNotNull(elementFunction.apply(t)), countFunction.applyAsInt(t)),
      (multiset1, multiset2) -> {
        multiset1.addAll(multiset2);
        return multiset1;
      },
      (Multiset<E> multiset) -> ImmutableMultiset.copyFromEntries(multiset.entrySet()));
}

static <T extends @Nullable Object, E extends @Nullable Object, M extends Multiset<E>>
      Collector<T, ?, M> toMultiset(
          Function<? super T, E> elementFunction,
          ToIntFunction<? super T> countFunction,
          Supplier<M> multisetSupplier) {
    checkNotNull(elementFunction);
    checkNotNull(countFunction);
    checkNotNull(multisetSupplier);
    return Collector.of(
        multisetSupplier,
        (ms, t) -> ms.add(elementFunction.apply(t), countFunction.applyAsInt(t)),
        (ms1, ms2) -> {
          ms1.addAll(ms2);
          return ms1;
        });
  }

static <
          T extends @Nullable Object,
          K extends @Nullable Object,
          V extends @Nullable Object,
          M extends Multimap<K, V>>
      Collector<T, ?, M> toMultimap(
          Function<? super T, ? extends K> keyFunction,
          Function<? super T, ? extends V> valueFunction,
          Supplier<M> multimapSupplier) {
    checkNotNull(keyFunction);
    checkNotNull(valueFunction);
    checkNotNull(multimapSupplier);
    return Collector.of(
        multimapSupplier,
        (multimap, input) -> multimap.put(keyFunction.apply(input), valueFunction.apply(input)),
        (multimap1, multimap2) -> {
          multimap1.putAll(multimap2);
          return multimap1;
        });
  }

static <
          T extends @Nullable Object,
          K extends @Nullable Object,
          V extends @Nullable Object,
          M extends Multimap<K, V>>
      Collector<T, ?, M> flatteningToMultimap(
          Function<? super T, ? extends K> keyFunction,
          Function<? super T, ? extends Stream<? extends V>> valueFunction,
          Supplier<M> multimapSupplier) {
    checkNotNull(keyFunction);
    checkNotNull(valueFunction);
    checkNotNull(multimapSupplier);
    return Collector.of(
        multimapSupplier,
        (multimap, input) -> {
          K key = keyFunction.apply(input);
          Collection<V> valuesForKey = multimap.get(key);
          valueFunction.apply(input).forEachOrdered(valuesForKey::add);
        },
        (multimap1, multimap2) -> {
          multimap1.putAll(multimap2);
          return multimap1;
        });
  }

@IgnoreJRERequirement // Users will use this only if they're already using streams.
  public static <T extends @Nullable Object, E>
      Collector<T, ?, ImmutableSortedMultiset<E>> toImmutableSortedMultiset(
          Comparator<? super E> comparator,
          Function<? super T, ? extends E> elementFunction,
          ToIntFunction<? super T> countFunction) {
    checkNotNull(comparator);
    checkNotNull(elementFunction);
    checkNotNull(countFunction);
    return Collector.of(
        () -> TreeMultiset.create(comparator),
        (multiset, t) -> mapAndAdd(t, multiset, elementFunction, countFunction),
        (multiset1, multiset2) -> {
          multiset1.addAll(multiset2);
          return multiset1;
        },
        (Multiset<E> multiset) -> copyOfSortedEntries(comparator, multiset.entrySet()));
  }

static <V2 extends @Nullable Object, K extends @Nullable Object, V1 extends @Nullable Object>
      Entry<K, V2> transformEntry(
          EntryTransformer<? super K, ? super V1, V2> transformer, Entry<K, V1> entry) {
    checkNotNull(transformer);
    checkNotNull(entry);
    return new AbstractMapEntry<K, V2>() {
      @Override
      @ParametricNullness
      public K getKey() {
        return entry.getKey();
      }

      @Override
      @ParametricNullness
      public V2 getValue() {
        return transformer.transformEntry(entry.getKey(), entry.getValue());
      }
    };
  }

static <T extends @Nullable Object, R, C, V>
      Collector<T, ?, ImmutableTable<R, C, V>> toImmutableTable(
          Function<? super T, ? extends R> rowFunction,
          Function<? super T, ? extends C> columnFunction,
          Function<? super T, ? extends V> valueFunction) {
    checkNotNull(rowFunction, "rowFunction");
    checkNotNull(columnFunction, "columnFunction");
    checkNotNull(valueFunction, "valueFunction");
    return Collector.of(
        (Supplier<ImmutableTable.Builder<R, C, V>>) ImmutableTable.Builder::new,
        (builder, t) ->
            builder.put(rowFunction.apply(t), columnFunction.apply(t), valueFunction.apply(t)),
        ImmutableTable.Builder::combine,
        ImmutableTable.Builder::buildOrThrow);
  }

static <
          T extends @Nullable Object,
          R extends @Nullable Object,
          C extends @Nullable Object,
          V,
          I extends Table<R, C, V>>
      Collector<T, ?, I> toTable(
          Function<? super T, ? extends R> rowFunction,
          Function<? super T, ? extends C> columnFunction,
          Function<? super T, ? extends V> valueFunction,
          Supplier<I> tableSupplier) {
    return TableCollectors.<T, R, C, V, I>toTable(
        rowFunction,
        columnFunction,
        valueFunction,
        (v1, v2) -> {
          throw new IllegalStateException("Conflicting values " + v1 + " and " + v2);
        },
        tableSupplier);
  }

@IgnoreJRERequirement // Users will use this only if they're already using streams.
  public static <T extends @Nullable Object> Collector<T, ?, BloomFilter<T>> toBloomFilter(
      Funnel<? super T> funnel, long expectedInsertions, double fpp) {
    checkNotNull(funnel);
    checkArgument(
        expectedInsertions >= 0, "Expected insertions (%s) must be >= 0", expectedInsertions);
    checkArgument(fpp > 0.0, "False positive probability (%s) must be > 0.0", fpp);
    checkArgument(fpp < 1.0, "False positive probability (%s) must be < 1.0", fpp);
    return Collector.of(
        () -> create(funnel, expectedInsertions, fpp),
        BloomFilter::put,
        (bf1, bf2) -> {
          bf1.putAll(bf2);
          return bf1;
        },
        Collector.Characteristics.UNORDERED,
        Collector.Characteristics.CONCURRENT);
  }

public ReadOnlyClassToSerializerMap getReadOnlyLookupMap()
    {
        ReadOnlyClassToSerializerMap m = _readOnlyMap.get();
        if (m != null) {
            return m;
        }
        return _makeReadOnlyLookupMap();
    }

    private ReadOnlyClassToSerializerMap _makeReadOnlyLookupMap() {
        // Use a dedicated lock so that rebuilding the read-only snapshot
        // does not block behind a long resolve() in addAndResolveNonTypedSerializer.
        // _sharedMap is thread-safe (PrivateMaxEntriesMap) so iterating it
        // concurrently with put() is safe (weakly consistent).
        synchronized (_readOnlyMapLock) {
            ReadOnlyClassToSerializerMap m = _readOnlyMap.get();
            if (m == null) {
                m = ReadOnlyClassToSerializerMap.from(this, _sharedMap);
                _readOnlyMap.set(m);
            }
            return m;
        }
    }

@Override
    public void writeInt8(byte[] values) {
        if (values == null) {
            writeArrayNull();
            return;
        }

        int off = this.off;
        int size = values.length;
        int minCapacity = off + 6 + values.length * 2;
        byte[] bytes = this.bytes;
        if (minCapacity > bytes.length) {
            bytes = grow(minCapacity);
        }

        if (size <= ARRAY_FIX_LEN) {
            bytes[off++] = (byte) (BC_ARRAY_FIX_MIN + size);
        } else {
            bytes[off] = BC_ARRAY;
            off = JSONB.IO.writeInt32(bytes, off + 1, size);
        }

        for (int val : values) {
            if (val < BC_INT32_NUM_MIN || val > BC_INT32_NUM_MAX) {
                bytes[off++] = (byte) (BC_INT32_BYTE_ZERO + (val >> 8));
            }
            bytes[off++] = (byte) val;
        }
        this.off = off;
    }

private static Map<String, DateTimeZone> buildDefaultTimeZoneNames() {
    // names from RFC-822 / JDK
    // this is all very US-centric and dubious, but perhaps it will help some
    Map<String, DateTimeZone> map = new LinkedHashMap<String, DateTimeZone>();
    map.put("UT", DateTimeZone.UTC);
    map.put("UTC", DateTimeZone.UTC);
    map.put("GMT", DateTimeZone.UTC);
    put(map, "EST", "America/New_York");
    put(map, "EDT", "America/New_York");
    put(map, "CST", "America/Chicago");
    put(map, "CDT", "America/Chicago");
    put(map, "MST", "America/Denver");
    put(map, "MDT", "America/Denver");
    put(map, "PST", "America/Los_Angeles");
    put(map, "PDT", "America/Los_Angeles");
    return Collections.unmodifiableMap(map);
}

public static boolean isConvertibleToStream(@Nullable Class<?> type) {
	if (type == null || type == void.class) {
		return false;
	}
	return (Stream.class.isAssignableFrom(type)//
			|| DoubleStream.class.isAssignableFrom(type)//
			|| IntStream.class.isAssignableFrom(type)//
			|| LongStream.class.isAssignableFrom(type)//
			|| Iterable.class.isAssignableFrom(type)//
			|| Iterator.class.isAssignableFrom(type)//
			|| Object[].class.isAssignableFrom(type)//
			|| (type.isArray() && type.getComponentType().isPrimitive())//
			|| findIteratorMethod(type).isPresent());
}

private ListBuffer<JCTree.JCStatement> genWriteBigDecimal(
        MethodWriterContext mwc,
        AttributeInfo attributeInfo,
        int i
) {
    ListBuffer<JCTree.JCStatement> stmts = new ListBuffer<>();

    String type = attributeInfo.type.toString();
    JCTree.JCVariableDecl fieldValue = defVar("bigDecimal" + i, qualIdent(type), genWriteFieldValue(attributeInfo, mwc.object, mwc.beanType));
    stmts.append(fieldValue);

    stmts.append(
            defIf(
                    or(notNull(fieldValue), isEnable(mwc.contextFeatures, WriteNulls)),
                    block(
                            genWriteFieldName(mwc, attributeInfo, i),
                            exec(mwc.jsonWriterMethod("writeDecimal", fieldValue))
                    )
            )
    );
    return stmts;
}
